import{_ as e,c as s,o as t,a1 as i}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"v1.0.0-v1.0.1: релиз | opencode-mystatus","description":"Узнайте о релизе v1.0.0 с поддержкой OpenAI, 智谱 AI, Google Cloud и исправлении команды слеша v1.0.1.","frontmatter":{"title":"v1.0.0-v1.0.1: релиз | opencode-mystatus","sidebarTitle":"v1.0.0-v1.0.1","description":"Узнайте о релизе v1.0.0 с поддержкой OpenAI, 智谱 AI, Google Cloud и исправлении команды слеша v1.0.1.","subtitle":"v1.0.0-v1.0.1: релиз","tags":["версия","журнал изменений","v1.0.0","v1.0.1"],"order":2},"headers":[],"relativePath":"ru/vbgate/opencode-mystatus/changelog/v100-v101/index.md","filePath":"ru/vbgate/opencode-mystatus/changelog/v100-v101/index.md"}'),n={name:"ru/vbgate/opencode-mystatus/changelog/v100-v101/index.md"};function o(l,a,d,p,h,r){return t(),s("div",null,[...a[0]||(a[0]=[i(`<h1 id="v1-0-0-v1-0-1-начальныи-выпуск-и-исправление-команды-слеша" tabindex="-1">v1.0.0 - v1.0.1：начальный выпуск и исправление команды слеша <a class="header-anchor" href="#v1-0-0-v1-0-1-начальныи-выпуск-и-исправление-команды-слеша" aria-label="Permalink to &quot;v1.0.0 - v1.0.1：начальный выпуск и исправление команды слеша&quot;">​</a></h1><h2 id="обзор-версии" tabindex="-1">Обзор версии <a class="header-anchor" href="#обзор-версии" aria-label="Permalink to &quot;Обзор версии&quot;">​</a></h2><p><strong>v1.0.0</strong> (2026-01-11) — это начальная версия opencode-mystatus, которая принесла основные функции запроса квоты для нескольких платформ.</p><p><strong>v1.0.1</strong> (2026-01-11) немедленно последовала, исправив ключевую проблему с поддержкой команд слеша.</p><hr><h2 id="v1-0-1-исправление-команды-слеша" tabindex="-1">v1.0.1 - Исправление команды слеша <a class="header-anchor" href="#v1-0-1-исправление-команды-слеша" aria-label="Permalink to &quot;v1.0.1 - Исправление команды слеша&quot;">​</a></h2><h3 id="исправленные-проблемы" tabindex="-1">Исправленные проблемы <a class="header-anchor" href="#исправленные-проблемы" aria-label="Permalink to &quot;Исправленные проблемы&quot;">​</a></h3><p><strong>Включение каталога <code>command/</code> в пакет npm</strong></p><ul><li><strong>Описание проблемы</strong>: после выпуска v1.0.0 команда слеша <code>/mystatus</code> не работала должным образом</li><li><strong>Анализ причины</strong>: при упаковке npm каталог <code>command/</code> был пропущен, что привело к тому, что OpenCode не мог распознать команду слеша</li><li><strong>Решение</strong>: обновление поля <code>files</code> в <code>package.json</code>, чтобы убедиться, что каталог <code>command/</code> включён в публикуемый пакет</li><li><strong>Область влияния</strong>: влияет только на пользователей, установленных через npm, ручная установка не затронута</li></ul><h3 id="рекомендации-по-обновлению" tabindex="-1">Рекомендации по обновлению <a class="header-anchor" href="#рекомендации-по-обновлению" aria-label="Permalink to &quot;Рекомендации по обновлению&quot;">​</a></h3><p>Если вы уже установили v1.0.0, рекомендуется немедленно обновиться до v1.0.1, чтобы получить полную поддержку команд слеша:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">## Обновление до последней версии</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @vbgate/opencode-mystatus</span></span></code></pre></div><hr><h2 id="v1-0-0-начальныи-выпуск" tabindex="-1">v1.0.0 - Начальный выпуск <a class="header-anchor" href="#v1-0-0-начальныи-выпуск" aria-label="Permalink to &quot;v1.0.0 - Начальный выпуск&quot;">​</a></h2><h3 id="новые-функции" tabindex="-1">Новые функции <a class="header-anchor" href="#новые-функции" aria-label="Permalink to &quot;Новые функции&quot;">​</a></h3><p><strong>1. Запрос квоты нескольких платформ</strong></p><p>Поддерживает запрос квоты использования следующих платформ одним кликом:</p><table tabindex="0"><thead><tr><th>Платформа</th><th>Поддерживаемые типы подписок</th><th>Тип квоты</th></tr></thead><tbody><tr><td>OpenAI</td><td>Plus/Team/Pro</td><td>Лимит за 3 часа、Лимит за 24 часа</td></tr><tr><td>智谱 AI</td><td>Coding Plan</td><td>Лимит Token за 5 часов、Ежемесячная квота MCP</td></tr><tr><td>Google Cloud</td><td>Antigravity</td><td>G3 Pro、G3 Image、G3 Flash、Claude</td></tr></tbody></table><p><strong>2. Визуализированные индикаторы прогресса</strong></p><p>Интуитивно отображает использование квоты:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>OpenAI (user@example.com)</span></span>
<span class="line"><span>━━━━━━━━━━━━━━━━━━━━ 75%</span></span>
<span class="line"><span>Использовано 750 / 1000 запросов</span></span></code></pre></div><p><strong>3. Многоязычная поддержка</strong></p><ul><li>Китайский (упрощённый)</li><li>Английский</li></ul><p>Язык определяется автоматически, без необходимости ручного переключения.</p><p><strong>4. Маскировка API Key</strong></p><p>Все конфиденциальные данные (API Key、OAuth Token) автоматически маскируются при отображении:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>智谱 AI (zhipuai-coding-plan)</span></span>
<span class="line"><span>API Key: sk-a1b2****xyz</span></span></code></pre></div><hr><h2 id="способ-использования" tabindex="-1">Способ использования <a class="header-anchor" href="#способ-использования" aria-label="Permalink to &quot;Способ использования&quot;">​</a></h2><h3 id="команда-слеша-рекомендуется" tabindex="-1">Команда слеша (рекомендуется) <a class="header-anchor" href="#команда-слеша-рекомендуется" aria-label="Permalink to &quot;Команда слеша (рекомендуется)&quot;">​</a></h3><p>В OpenCode введите:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/mystatus</span></span></code></pre></div><h3 id="естественныи-язык" tabindex="-1">Естественный язык <a class="header-anchor" href="#естественныи-язык" aria-label="Permalink to &quot;Естественный язык&quot;">​</a></h3><p>Вы также можете спросить на естественном языке:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Посмотреть все квоты моих AI платформ</span></span></code></pre></div><hr><h2 id="руководство-по-обновлению" tabindex="-1">Руководство по обновлению <a class="header-anchor" href="#руководство-по-обновлению" aria-label="Permalink to &quot;Руководство по обновлению&quot;">​</a></h2><h3 id="обновление-с-v1-0-0-до-v1-0-1" tabindex="-1">Обновление с v1.0.0 до v1.0.1 <a class="header-anchor" href="#обновление-с-v1-0-0-до-v1-0-1" aria-label="Permalink to &quot;Обновление с v1.0.0 до v1.0.1&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @vbgate/opencode-mystatus</span></span></code></pre></div><p>После обновления перезапустите OpenCode, чтобы использовать команду слеша <code>/mystatus</code>.</p><h3 id="первичная-установка" tabindex="-1">Первичная установка <a class="header-anchor" href="#первичная-установка" aria-label="Permalink to &quot;Первичная установка&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @vbgate/opencode-mystatus</span></span></code></pre></div><p>После установки введите <code>/mystatus</code> в OpenCode, чтобы запросить квоту всех платформ.</p><hr><h2 id="известные-ограничения" tabindex="-1">Известные ограничения <a class="header-anchor" href="#известные-ограничения" aria-label="Permalink to &quot;Известные ограничения&quot;">​</a></h2><ul><li>v1.0.0 не поддерживает GitHub Copilot (добавлено в v1.2.0)</li><li>v1.0.0 не поддерживает Z.ai (добавлено в v1.1.0)</li></ul><p>Если вы хотите использовать эти функции, обновитесь до последней версии.</p><hr><h2 id="следующие-шаги" tabindex="-1">Следующие шаги <a class="header-anchor" href="#следующие-шаги" aria-label="Permalink to &quot;Следующие шаги&quot;">​</a></h2><p>Просмотрите <a href="./../v120-v124/">журнал изменений v1.2.0 - v1.2.4</a>, чтобы узнать о новых функциях, таких как поддержка GitHub Copilot.</p>`,50)])])}const v=e(n,[["render",o]]);export{u as __pageData,v as default};
